private enum class PlatformTab{ASSESS,EXAM,REPORT,TRUST,TEACHER,DELIVERY}
@Composable fun Phase3PlatformWorkspace(onExit:()->Unit){var tab by rememberSaveable{mutableStateOf(PlatformTab.ASSESS)};BoxWithConstraints(Modifier.fillMaxSize()){val window=AdaptiveLayoutPolicy.classify(maxWidth.value.toInt(),maxHeight.value.toInt());val layout=AdaptiveLayoutPolicy.layout(window);Column(Modifier.fillMaxSize()){Row(Modifier.padding(8.dp),horizontalArrangement=Arrangement.spacedBy(8.dp)){OutlinedButton(onExit){Text("Back")};Column{Text("PHASE 3 · TRUSTED SCHOOL PLATFORM",style=MaterialTheme.typography.titleMedium);Text("${window.name.replace('_',' ')} · ${layout.panes.size} adaptive pane(s)",style=MaterialTheme.typography.labelSmall)}};ScrollableTabRow(tab.ordinal){PlatformTab.entries.forEach{t->Tab(tab==t,{tab=t},text={Text(t.name.lowercase().replaceFirstChar(Char::uppercase))})}};when(tab){PlatformTab.ASSESS->AssessmentPane();PlatformTab.EXAM->ExamPane();PlatformTab.REPORT->ReportPane();PlatformTab.TRUST->TrustPane();PlatformTab.TEACHER->TeacherPane();PlatformTab.DELIVERY->DeliveryPane()}}}}

@Composable private fun AssessmentPane(){val rubric=Phase3Reference.rubrics.first();val engine=remember{PartialCreditAssessmentEngine(Phase3Reference.validators)};var formula by rememberSaveable{mutableStateOf("2x + 4 = 10")};var transform by rememberSaveable{mutableStateOf("x=3")};var reason by rememberSaveable{mutableStateOf("because substituting 3 preserves equality")};var result by remember{mutableStateOf<StepAssessmentResult?>(null)};LazyColumn(Modifier.fillMaxSize().padding(16.dp),verticalArrangement=Arrangement.spacedBy(10.dp)){item{Text("Step-scored assessment",style=MaterialTheme.typography.headlineSmall);Text("Method, transformation and conclusion are scored independently; follow-through credit never hides the originating error.")};item{OutlinedTextField(formula,{formula=it},Modifier.fillMaxWidth(),label={Text("1 · Equation")});OutlinedTextField(transform,{transform=it},Modifier.fillMaxWidth(),label={Text("2 · Transformation")});OutlinedTextField(reason,{reason=it},Modifier.fillMaxWidth(),label={Text("3 · Verification")});Button({result=engine.score(rubric,listOf(CriterionAttempt("formula",formula),CriterionAttempt("transform",transform),CriterionAttempt("conclusion",reason)))}){Text("Score steps locally")}};result?.let{r->item{Card(Modifier.fillMaxWidth().semantics{contentDescription="Assessment ${r.earnedMarks} of ${r.maximumMarks}; first invalid ${r.firstInvalidCriterionId?:"none"}"}){Column(Modifier.padding(12.dp)){Text("${r.earnedMarks} / ${r.maximumMarks} marks",style=MaterialTheme.typography.titleLarge);r.scores.forEach{Text("${it.criterionId}: ${it.earned}/${it.maximum}${if(it.followThrough)" · follow-through" else ""} — ${it.feedback}")};Text(r.suggestedRetry)}}}}}}

@Composable private fun ExamPane(){val manifest=ReferenceExaminations.manifests.first();val runtime=remember{LocalExamRuntime(manifest,ReferenceExaminations.originalQuestions(manifest))};var session by rememberSaveable(stateSaver=androidx.compose.runtime.saveable.Saver(save={listOf(it.id,it.remainingSeconds.toString(),it.status.name)},restore={runtime.newSession(it[0]).copy(remainingSeconds=it[1].toInt(),status=ExamSessionStatus.valueOf(it[2]))})){mutableStateOf(runtime.newSession("local-exam"))};LazyColumn(Modifier.fillMaxSize().padding(16.dp),verticalArrangement=Arrangement.spacedBy(10.dp)){item{Text("CBSE examination simulator",style=MaterialTheme.typography.headlineSmall);Text("${manifest.classLevel.name.replace('_',' ')} ${manifest.subject} · ${manifest.totalMarks} marks · ${manifest.durationMinutes} minutes");Text("Original, current-curriculum mapped practice; hidden answers remain unavailable before submission.")};item{Text("Status: ${session.status} · Remaining ${session.remainingSeconds/60}:${(session.remainingSeconds%60).toString().padStart(2,'0')}");Row(horizontalArrangement=Arrangement.spacedBy(8.dp)){Button({session=runtime.start(session,Instant.now())},enabled=session.status==ExamSessionStatus.NOT_STARTED){Text("Start")};OutlinedButton({session=runtime.tick(session,60)},enabled=session.status==ExamSessionStatus.ACTIVE){Text("Advance 1 min")};Button({session=runtime.submit(session)},enabled=session.status==ExamSessionStatus.ACTIVE){Text("Final review & submit")}}};item{Text("Question palette",style=MaterialTheme.typography.titleMedium);runtime.palette(session).entries.take(12).forEach{Text("${it.key}: ${it.value}")}}}}

@Composable private fun ReportPane(){val service=remember{LocalLearningIntelligenceService()};val report=remember{EvidenceReportEngine().create("local-learner",service.repository.all())};LazyColumn(Modifier.fillMaxSize().padding(16.dp),verticalArrangement=Arrangement.spacedBy(8.dp)){item{Text("Evidence-based progress",style=MaterialTheme.typography.headlineSmall);Text(report.examReadiness);report.limitation?.let{Text(it,color=MaterialTheme.colorScheme.tertiary)};Text("Mastered: ${report.mastered.size} · Proficient: ${report.proficient.size} · Learning: ${report.learning.size}");Text(report.confidenceNote)};item{Text("Capabilities demonstrated",style=MaterialTheme.typography.titleMedium);report.capabilities.forEach{Text("${it.capability}: ${it.independent} independent, ${it.assisted} assisted, ${it.delayed} delayed")};if(report.capabilities.isEmpty())Text("Complete assessed activities to collect recall, explanation, calculation, construction, prediction, experiment, interpretation, application and retention evidence.")}}}

@Composable private fun TrustPane(){val lineage=ContentLineageRegistry.records.first();val counter=AuthoredCounterexampleEngine.generate("physics-current-consumed");LazyColumn(Modifier.fillMaxSize().padding(16.dp),verticalArrangement=Arrangement.spacedBy(10.dp)){item{Text("Source lineage & release governance",style=MaterialTheme.typography.headlineSmall);Text(ContentLineageRegistry.learnerSummary(lineage.contentId).orEmpty());Text("Curriculum: ${lineage.curriculumNodeIds.joinToString()} · review ${lineage.lastReviewedAt}");Text("AI involvement: ${lineage.aiInvolvement}")};item{Card(Modifier.fillMaxWidth()){Column(Modifier.padding(12.dp)){Text("Counterexample laboratory",style=MaterialTheme.typography.titleMedium);Text(counter.example);Text(counter.explanation)}}};item{val dimensions=DimensionalConsistencyValidator().validateVerified(Phase3Reference.formulas);Text("Dimensional build validation: ${if(dimensions.isEmpty())"all verified reference formulas consistent" else "${dimensions.size} blocking issue(s)"}");Text("Accessibility release gate is mandatory for interactive assets.")}}}

@Composable private fun TeacherPane(){val classroom=ReferenceTeacherFlows.mathClass;val assignment=ReferenceTeacherFlows.mathAssignment;val engine=remember{TeacherPlatformEngine()};LaunchedEffect(Unit){engine.validate(classroom,assignment)};LazyColumn(Modifier.fillMaxSize().padding(16.dp),verticalArrangement=Arrangement.spacedBy(10.dp)){item{Text("Teacher classroom",style=MaterialTheme.typography.headlineSmall);Text(classroom.title);Text("${classroom.learnerIds.size} learners · minimal local role data");Text("Assignment: ${assignment.title}");assignment.conceptIds.forEach{Text("• $it")}};item{Text("Privacy-preserving mastery map",style=MaterialTheme.typography.titleMedium);Text("Only assigned learner evidence is visible. Private notes remain learner-only. Misconception clusters require at least five learners.");Text("Differentiation: ${assignment.differentiationRules.joinToString{it.path.name.replace('_',' ')}}")}}}

@Composable private fun DeliveryPane(){var locale by rememberSaveable{mutableStateOf("en-IN")};var mode by rememberSaveable{mutableStateOf(TermDisplayMode.BOTH)};var frame by rememberSaveable{mutableFloatStateOf(16f)};val governor=remember{PerformanceQualityGovernor()};val quality=governor.quality(governor.decide(PerformanceSignals(frame.toDouble(),if(frame>20)8.0 else 1.0,false,false,false,false)));LazyColumn(Modifier.fillMaxSize().padding(16.dp),verticalArrangement=Arrangement.spacedBy(10.dp)){item{Text("Language, offline continuity & performance",style=MaterialTheme.typography.headlineSmall);Row(horizontalArrangement=Arrangement.spacedBy(6.dp)){IndianLanguageLayer.supportedLocales.forEach{l->FilterChip(locale==l,{locale=l},label={Text(l)})}};Text("${IndianLanguageLayer.display("velocity",locale,mode)} · ${IndianLanguageLayer.display("equation",locale,mode)} · ${IndianLanguageLayer.display("cell",locale,mode)}");Button({mode=TermDisplayMode.entries[(mode.ordinal+1)%TermDisplayMode.entries.size]}){Text("Term mode: ${mode.name}")}};item{Text("Rendering quality: ${quality.level}");Slider(frame,{frame=it},valueRange=12f..35f);Text("Frame signal ${frame.toInt()} ms · particles ${quality.particleCount} · graph ${quality.graphRefreshHz} Hz");Text("Formula calculations, assessment values and stored data never change with rendering quality.")};item{Text("Offline-first",style=MaterialTheme.typography.titleMedium);Text("No-account mode remains fully usable. Progress merges by evidence; notes retain versions; bookmarks use tombstones; submissions are immutable; feedback is append-only.")}}}
